        p3After: T('.', '.', '。', '.'),
        bullet0: T('कमीशनिंग पर साइट-विशिष्ट नेटवर्क डिज़ाइन', 'تصميم شبكة خاص بالموقع عند التشغيل', '試運転時のサイト固有のネットワーク設計', 'কমিশনিং-এ সাইট-নির্দিষ্ট নেটওয়ার্ক ডিজাইন'),
        bullet1: T('NECTYR तक सुरक्षित टेलीमेट्री पथ', 'مسار قياس عن بعد آمن إلى NECTYR', 'NECTYRへの安全なテレメトリパス', 'NECTYR-এ সুরক্ষিত টেলিমেট্রি পথ'),
        bullet2: T('ट्रक रोल होने से पहले रिमोट डायग्नोस्टिक्स', 'التشخيص عن بعد قبل إرسال الشاحنات', 'トラック出動前の遠隔診断', 'ট্রাক গমনের আগে রিমোট ডায়াগনস্টিকস'),
        imageAlt: T('Taypro स्वचालित, अर्ध-स्वचालित और ट्रैकर सोलर पैनल सफाई रोबोट', 'روبوتات Taypro الأوتوماتيكية وشبه الأوتوماتيكية والتتبع لتنظيف الألواح الشمسية', 'Tayproの自動、半自動、およびトラッカーソーラーパネル清掃ロボット', 'Taypro স্বয়ংক্রিয়, অর্ধ-স্বয়ংক্রিয়, এবং ট্র্যাকার সোলার প্যানেল পরিষ্কারের রোবট'),
